package ethapi

import (
	"context"
	"testing"

	"github.com/ethereum/go-ethereum/common"
	"github.com/ethereum/go-ethereum/common/hexutil"
	"github.com/ethereum/go-ethereum/consensus/beacon"
	"github.com/ethereum/go-ethereum/consensus/ethash"
	"github.com/ethereum/go-ethereum/core"
	"github.com/ethereum/go-ethereum/core/rawdb"
	"github.com/ethereum/go-ethereum/core/types"
	"github.com/ethereum/go-ethereum/crypto"
	"github.com/ethereum/go-ethereum/params"
	"github.com/ethereum/go-ethereum/rlp"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestGetBlockReceipt tests the GetBlockReceipt JSON-RPC API
// This test saves actual block data to the database and retrieves the block receipt using the API
func TestGetBlockReceipt(t *testing.T) {
	t.Parallel()

	var (
		genBlocks = 0
		genesis   = &core.Genesis{
			Config:        params.MergedTestChainConfig,
			ExcessBlobGas: new(uint64),
			BlobGasUsed:   new(uint64),
			Alloc:         types.GenesisAlloc{},
		}
		backend = newTestBackend(t, genBlocks, genesis, beacon.New(ethash.NewFaker()), func(i int, b *core.BlockGen) {})
		api     = NewBlockChainAPI(backend)
	)

	// seedData stores Block and Receipts for specific hash and height into DB
	seedData := func(t *testing.T, blockHash common.Hash, height uint64, headerBytes []byte, bodyBytes []byte, receiptsBytes []byte) {
		t.Helper()

		// Decode Header, Body, and Receipts
		blockHeader := &types.Header{}
		err := rlp.DecodeBytes(headerBytes, blockHeader)
		require.NoError(t, err)

		blockBody := &types.Body{}
		err = rlp.DecodeBytes(bodyBytes, blockBody)
		require.NoError(t, err)

		receipts := &types.Receipts{}
		err = rlp.DecodeBytes(receiptsBytes, receipts)
		require.NoError(t, err)

		block := types.NewBlockWithHeader(blockHeader).WithBody(*blockBody)

		// Store data into DB
		rawdb.WriteHeaderNumber(backend.ChainDb(), blockHash, height)
		rawdb.WriteBlock(backend.ChainDb(), block)
		rawdb.WriteReceipts(backend.ChainDb(), blockHash, height, *receipts)

		t.Cleanup(func() {
			rawdb.DeleteReceipts(backend.ChainDb(), blockHash, height)
			rawdb.DeleteBlock(backend.ChainDb(), blockHash, height)
			rawdb.DeleteHeaderNumber(backend.ChainDb(), blockHash)
		})
	}

	// createBlockReceiptBloom creates a Bloom for block receipt
	createBlockReceiptBloom := func(logs []*types.Log) types.Bloom {
		receipt := &types.Receipt{
			Type:              types.LegacyTxType,
			PostState:         []byte{},
			CumulativeGasUsed: 0,
			Logs:              logs,
		}

		return types.CreateBloom(receipt)
	}

	// createExpectedResponse creates expected JSON-RPC response data
	createExpectedResponse := func(blockHash common.Hash, blockNumber uint64, receiptIndex int, logs []*types.Log) map[string]interface{} {
		return map[string]interface{}{
			"blockHash":         blockHash,
			"blockNumber":       hexutil.Uint64(blockNumber),
			"transactionHash":   blockHash,
			"transactionIndex":  hexutil.Uint64(receiptIndex),
			"from":              common.Address{},
			"to":                nil,
			"gasUsed":           hexutil.Uint64(0),
			"cumulativeGasUsed": hexutil.Uint64(0),
			"contractAddress":   nil,
			"logs":              logs,
			"logsBloom":         createBlockReceiptBloom(logs),
			"type":              hexutil.Uint(0),
			"status":            hexutil.Uint(types.ReceiptStatusSuccessful),
		}
	}

	tests := []struct {
		name      string
		height    uint64
		blockHash common.Hash
		// DB data
		headerBytes   []byte
		bodyBytes     []byte
		receiptsBytes []byte
		// Expected parameters
		blockReceiptIndex int
		systemLogs        []*types.Log
		expectedValue     map[string]interface{}
	}{
		{
			// Alfajores block 10
			name:              "should return empty receipt when system logs are not included",
			height:            10,
			blockHash:         common.HexToHash("0x88357030fa9168bbe0c8562c82cfe223e0153577d2794ddbff4efde2275b0498"),
			headerBytes:       common.FromHex(""),
			bodyBytes:         common.FromHex("0xc2c0c0"),
			receiptsBytes:     common.FromHex("0xc0"),
			blockReceiptIndex: 0,
			systemLogs:        []*types.Log{},
		},
		{
			// Alfajores block 10000
			name:              "should return a receipt with system logs at the first index when the block has no transactions",
			height:            10000,
			blockHash:         common.HexToHash("0x103a73e9f82d8262a0d9aac30d40d076ca04fd1e386fbf68ce55077d53044620"),
			headerBytes:       common.FromHex(""),
			bodyBytes:         common.FromHex("0xc2c0c0"),
			receiptsBytes:     common.FromHex(""),
			blockReceiptIndex: 0,
			systemLogs: []*types.Log{
				{
					BlockNumber: 10000,
					TxHash:      common.HexToHash("0x103a73e9f82d8262a0d9aac30d40d076ca04fd1e386fbf68ce55077d53044620"),
					BlockHash:   common.HexToHash("0x103a73e9f82d8262a0d9aac30d40d076ca04fd1e386fbf68ce55077d53044620"),
					TxIndex:     0,
					Address:     common.HexToAddress("0xd0Bf87a5936ee17014a057143a494Dc5C5d51E5e"), // GasPriceMinimumProxy
					Topics: []common.Hash{
						common.Hash(crypto.Keccak256([]byte("GasPriceMinimumUpdated(uint256)"))),
					},
					Data: common.FromHex("0x0000000000000000000000000000000000000000000000000000000005f5e100"), // 0.1 GWei
				},
			},
		},
		{
			// Alfajores block 10000000
			name:              "should return a receipt with system logs at the last index when the block has transactions",
			height:            10000000,
			blockHash:         common.HexToHash("0xea3090f7c584b577ac095a7ecf791e6a2c62cce3fda3049d84859f97fd33b237"),
			headerBytes:       common.FromHex(""),
			bodyBytes:         common.FromHex(""),
			receiptsBytes:     common.FromHex(""),
			blockReceiptIndex: 4,
			systemLogs: []*types.Log{
				{
					BlockNumber: 10000000,
					TxHash:      common.HexToHash("0xea3090f7c584b577ac095a7ecf791e6a2c62cce3fda3049d84859f97fd33b237"),
					BlockHash:   common.HexToHash("0xea3090f7c584b577ac095a7ecf791e6a2c62cce3fda3049d84859f97fd33b237"),
					TxIndex:     4,
					Index:       18,
					Address:     common.HexToAddress("0xd0Bf87a5936ee17014a057143a494Dc5C5d51E5e"), // GasPriceMinimumProxy
					Topics: []common.Hash{
						common.Hash(crypto.Keccak256([]byte("GasPriceMinimumUpdated(uint256)"))),
					},
					Data: common.FromHex("0x0000000000000000000000000000000000000000000000000000000005f5e100"), // 0.1 GWei
				},
			},
		},
	}

	for _, test := range tests {
		t.Run(test.name, func(t *testing.T) {
			seedData(t, test.blockHash, test.height, test.headerBytes, test.bodyBytes, test.receiptsBytes)

			expectedValue := createExpectedResponse(test.blockHash, test.height, test.blockReceiptIndex, test.systemLogs)

			res, err := api.GetBlockReceipt(context.Background(), test.blockHash)
			require.NoError(t, err)
			assert.Equal(t, expectedValue, res)
		})
	}
}
